(function(){"use strict";var RESULT_HOLD_MS=3e3;function setState(a,state){a.classList.remove("is-loading","is-success","is-error");if(state){a.classList.add(state)}}document.addEventListener("click",function(e){var a=e.target.closest(".js-admin-link-ajax");if(!a)return;e.preventDefault();if(a.classList.contains("is-loading")||a.classList.contains("is-success")||a.classList.contains("is-error")){return}var url=a.getAttribute("data-ajax-url");var csrf=a.getAttribute("data-ajax-csrf")||"";if(!url)return;var fd=new FormData;fd.append("_csrf",csrf);setState(a,"is-loading");fetch(url,{method:"POST",credentials:"same-origin",headers:{"X-Requested-With":"XMLHttpRequest"},body:fd}).then(function(r){return r.ok}).catch(function(){return false}).then(function(ok){setState(a,ok?"is-success":"is-error");setTimeout(function(){setState(a,null)},RESULT_HOLD_MS)})})})();